import{c as e,Q as t,j as o,m as r}from"./chunks/framework.iD28w_5a.js";const h=JSON.parse('{"title":"030-gui-wm-basic-2 · 窗口管理器","description":"","frontmatter":{"title":"030-gui-wm-basic-2 · 窗口管理器"},"headers":[],"relativePath":"hands-on/030-gui-wm-basic-2.md","filePath":"hands-on/030-gui-wm-basic-2.md","lastUpdated":1779686691000}'),n={name:"hands-on/030-gui-wm-basic-2.md"};function d(i,a,s,p,l,c){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="_030-2-window-类与窗口管理器核心" tabindex="-1">030-2 Window 类与窗口管理器核心 <a class="header-anchor" href="#_030-2-window-类与窗口管理器核心" aria-label="Permalink to &quot;030-2 Window 类与窗口管理器核心&quot;">​</a></h1><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>上一章我们搞定了鼠标输入和事件队列，现在数据已经能从硬件流到 GUI 子系统了。但光有数据不行，还得有东西来消费这些数据——窗口。这一章我们要搭建的是 GUI 的骨架：Window 抽象和 WindowManager 单例。Window 封装了一个窗口该有的所有属性（位置、尺寸、标题栏、离屏画布），WindowManager 负责管理所有窗口的 Z-序、焦点、创建/销毁，以及把所有窗口合成到屏幕上。另外我们还要修一个差点让整个 GUI 挂掉的 ISR 栈对齐 bug。</p><p>完成本章后，你会看到一个可以创建多个窗口、用鼠标点击切换焦点、通过 Z-序正确重叠的桌面系统。每个窗口有蓝色标题栏、白色标题文字和红色关闭按钮。</p><p>知识前置：上一章的鼠标驱动和事件系统，tag 029 的 Canvas 双缓冲渲染。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="窗口的离屏画布与双缓冲" tabindex="-1">窗口的离屏画布与双缓冲 <a class="header-anchor" href="#窗口的离屏画布与双缓冲" aria-label="Permalink to &quot;窗口的离屏画布与双缓冲&quot;">​</a></h3><p>每个 Window 内部持有一个独立的 Canvas 作为离屏渲染缓冲区。这个 Canvas 的尺寸是窗口宽度 x（窗口高度 + 标题栏高度）。窗口的所有绘制操作（画标题栏、画内容）都先写到这个离屏画布上，最后由 WindowManager 的 compositing 过程一次性把所有窗口 blit 到屏幕画布。这样做的好处是避免窗口绘制过程中的闪烁——用户永远只看到最终合成好的完整帧。</p><p>Window 的 Canvas 通过 allocate_canvas 方法初始化，接收宽度 w 和总高度（h + TITLE_BAR_HEIGHT）。每次 resize 时也需要重新分配画布，不过现有内容会丢失。Window 是 non-copyable 的——因为每个 Window 独占一个 Canvas（Canvas 持有 back_buf_ 堆内存），如果允许拷贝，两个 Window 指向同一个 back_buf_ 会在析构时 double-free。</p><h3 id="z-序管理" tabindex="-1">Z-序管理 <a class="header-anchor" href="#z-序管理" aria-label="Permalink to &quot;Z-序管理&quot;">​</a></h3><p>多个窗口在屏幕上会互相遮挡，我们需要决定谁在上面。我们用数组的索引来表示 Z-序：index 0 是最底层窗口，index (count - 1) 是最顶层窗口。当用户点击一个窗口时，这个窗口被&quot;raise&quot;到最顶层——具体操作是把它从当前位置抽出来，后面的窗口依次往前挪一个位置，然后把它放到数组末尾。这是一个 O(n) 的操作，但对于我们最多 64 个窗口的场景完全够用。</p><p>raise 操作有一个小优化：如果窗口已经在最顶层（idx == count - 1），不需要移动数组元素，直接调用 update_focus 即可。这在快速连续点击同一个窗口时能省掉无效的数组操作。</p><h3 id="焦点管理" tabindex="-1">焦点管理 <a class="header-anchor" href="#焦点管理" aria-label="Permalink to &quot;焦点管理&quot;">​</a></h3><p>焦点决定哪个窗口接收键盘事件。我们的策略很简单：最顶层的窗口就是焦点窗口。每次窗口创建、销毁、raise 之后都要重新计算焦点——清除所有窗口的 focused 标记，然后给最顶层的那个设上。如果所有窗口都关了，焦点指针就是 nullptr，键盘事件就没人接。</p><p>update_focus 做两件事：先遍历所有窗口调用 set_focused(false)，然后检查 count 是否大于 0，如果是就给 windows_[count-1] 调用 set_focused(true) 并更新 focused_ 指针。这是一个 O(n) 操作，但 n 最大 64，完全可以忽略。</p><h3 id="isr-栈对齐——一个差点被忽略的致命-bug" tabindex="-1">ISR 栈对齐——一个差点被忽略的致命 bug <a class="header-anchor" href="#isr-栈对齐——一个差点被忽略的致命-bug" aria-label="Permalink to &quot;ISR 栈对齐——一个差点被忽略的致命 bug&quot;">​</a></h3><p>在写鼠标驱动的时候，Mouse::init() 操作 8042 控制器会触发一个虚假的 IRQ1。本来这不应该是问题——键盘的 IRQ handler 正常处理就好。但事实是，这个虚假中断直接触发了 #GP（General Protection Fault）。原因是 ISR stub 的栈对齐不满足 System V ABI。</p><p>x86_64 System V ABI 要求在执行 <code>call</code> 指令前 RSP 必须 16 字节对齐，这样 <code>call</code> 压入 8 字节返回地址后，被调函数入口处 RSP 等价于 8 mod 16。编译器依赖这个约定来生成 <code>movaps</code> 等 SSE 指令——这些指令要求操作数地址 16 字节对齐。</p><p>我们的 ISR stub 里，CPU 自动压入 5 个 qword（SS, RSP, RFLAGS, CS, RIP = 40 字节），然后 stub 压入 1 个 dummy error code + 15 个 GPR = 16 个 qword（128 字节），总共 168 字节。168 + 8（call 的返回地址）= 176，正好是 16 的倍数，意味着 handler 入口 RSP 等价于 0 mod 16，违反了 ABI。</p><p>修复方法很简单：在压完 GPR 之后、<code>call</code> 之前，额外压入一个 8 字节零值作为填充。然后传给 C 处理函数的 InterruptFrame* 指针用 <code>leaq 8(%rsp), %rdi</code> 跳过填充，处理函数返回后 <code>addq $8, %rsp</code> 弹出填充。这 8 字节的对齐填充让总栈量变成 176 字节，加上 call 的 8 字节 = 184，184 等价于 8 mod 16，处理函数入口对齐正确。</p><p>这个 bug 之前一直没触发，因为键盘处理函数恰好没有使用 XMM 寄存器。直到我们在 keyboard.cpp 里加了 GUI 双路分发代码（调用 Mouse::event_queue().enqueue），编译器才生成了 <code>movaps</code>，然后立刻在下一个虚假 IRQ1 上炸了。</p><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-window-类设计" tabindex="-1">Step 1: Window 类设计 <a class="header-anchor" href="#step-1-window-类设计" aria-label="Permalink to &quot;Step 1: Window 类设计&quot;">​</a></h3><p><strong>目标</strong>: 定义窗口的数据结构，包含位置、尺寸、标题、离屏画布、可见性和焦点标记。</p><p><strong>设计思路</strong>: Window 是一个非拷贝的类，通过 <code>new</code> 在堆上分配。构造函数接收标题字符串、初始位置 (x, y) 和内容区域尺寸 (w, h)，自动从静态计数器分配唯一 ID（初始值为 1，每次 new 递增），然后调用 allocate_canvas 初始化离屏画布。画布的总高度是 h + TITLE_BAR_HEIGHT（20px）。标题字符串存储在一个固定大小的 char 数组里（64 字节 = TITLE_MAX_LEN + 1），手动零填充并截断复制——因为我们的内核没有标准库，没有 strncpy 可用。</p><p>Window 提供的绘制方法包括 draw_title_bar（钢蓝色背景 0x00336699 + 白色标题文字 + 红色关闭按钮方块 0x00CC3333）和 draw_content（浅灰色内容区背景 0x00E0E0E0）。draw_title_bar 在标题栏底部画一条 1px 深灰色边框线分隔标题栏和内容区。关闭按钮位于标题栏右上角，水平方向离右边 3px，垂直居中，尺寸 14x14 像素。</p><p>blit_to 方法把整个窗口画布 blit 到目标画布的对应屏幕坐标位置。它在内部检查 visible 标记——不可见的窗口跳过 blit。目标坐标是 int32_t 类型，支持窗口被拖到屏幕外时的部分裁剪。</p><p><strong>实现约束</strong>: Window 是一个非虚的普通类，只有 draw_title_bar 和 draw_content 两个绘制方法，没有虚函数。hit testing 方法 contains 和 is_close_button_hit 都接收屏幕坐标，做矩形包含测试。</p><p><strong>验证</strong>: 构造几个 Window 对象，调用 draw_title_bar 和 draw_content，检查离屏画布上标题栏和内容区是否正确绘制。可以用 Canvas 的 blit 方法把窗口 blit 到屏幕画布上验证视觉效果。</p><h3 id="step-2-windowmanager-单例" tabindex="-1">Step 2: WindowManager 单例 <a class="header-anchor" href="#step-2-windowmanager-单例" aria-label="Permalink to &quot;Step 2: WindowManager 单例&quot;">​</a></h3><p><strong>目标</strong>: 实现窗口管理器，管理最多 64 个窗口的 Z-序数组。</p><p><strong>设计思路</strong>: WindowManager 使用 Meyers&#39; singleton（static local reference），全局只有一个实例。通过 instance() 静态方法获取引用。init 方法接收屏幕 Canvas 指针和 PSFFont 指针，这两个是合成和标题栏渲染的依赖，同时也重置所有状态（count、focused、dragging 等）。</p><p>窗口用指针数组管理——Window* 数组 windows_[64]，用 count_ 追踪有效数量。用指针的好处是 Z-序重排只需要挪指针（8 字节），不需要移动 Window 对象本身（Window 是 non-copyable 的，而且持有大量 Canvas 堆内存）。</p><p>创建新窗口时位置交错排布（每个窗口偏移 30px，用 count_ * 30 计算），避免完全重叠。create 方法在堆上 new 一个 Window，创建后立即绘制标题栏和内容（检查 font_ 非空才画标题栏），然后更新焦点。create 返回窗口 ID（0 表示失败，即数组满了）。销毁窗口时先 delete 对象、shift 数组、清空末尾槽位、减少计数，如果被销毁的是焦点窗口就重新计算焦点。</p><p><strong>实现约束</strong>: create 方法返回窗口 ID（0 表示失败，即满了）。destroy 通过 ID 查找窗口，找不到则忽略（find_index 返回 MAX_WINDOWS 表示未找到）。raise 方法如果窗口已经在最顶层则只更新焦点，不做无效移动。</p><p><strong>验证</strong>: 创建 3 个窗口，检查它们的位置交错、Z-序（后创建的在上面）、焦点指向最顶层的窗口。销毁中间的窗口，检查数组 shift 是否正确、焦点是否重新分配。</p><h3 id="step-3-compositing-桌面合成" tabindex="-1">Step 3: Compositing（桌面合成） <a class="header-anchor" href="#step-3-compositing-桌面合成" aria-label="Permalink to &quot;Step 3: Compositing（桌面合成）&quot;">​</a></h3><p><strong>目标</strong>: 每帧清屏，从底到顶 blit 所有可见窗口，画光标，flip。</p><p><strong>设计思路</strong>: composite 方法首先用桌面背景色（深青色 0x00224466）清屏，然后从 index 0 到 count-1 依次把每个 visible 的窗口 blit 到屏幕画布上。最后调用 draw_cursor 画一个 16x16 的箭头光标。</p><p>光标位图 k_cursor_bitmap 是一个 16 行的 uint16_t 数组，编码了经典箭头形状。MSB 是最左边的像素，1 表示填充，0 表示透明。对于每个填充像素，先画四个方向的描边像素（值 0x00000000，即黑色），再画中心像素（值 0x00FFFFFF，即白色）。光标位置从 Mouse::x() 和 Mouse::y() 获取，直接在屏幕画布上画。因为 draw_pixel 已经有边界检查，光标移到屏幕边缘时多余的像素会自动被裁剪。</p><p>全部画完后调用 screen-&gt;flip() 呈现到硬件帧缓冲区。</p><p><strong>踩坑预警</strong>: draw_pixel 调用时坐标可能是负数（窗口被拖到屏幕外）。Canvas 的 draw_pixel 接受 uint32_t 坐标，所以传参前要做边界检查。blit 方法使用 int32_t 的目标坐标正是为了处理这种部分离屏的情况。</p><p><strong>验证</strong>: 创建几个窗口，调用 composite，确认屏幕上能看到所有窗口正确叠加，光标在正确的位置。</p><h3 id="step-4-修复-isr-栈对齐" tabindex="-1">Step 4: 修复 ISR 栈对齐 <a class="header-anchor" href="#step-4-修复-isr-栈对齐" aria-label="Permalink to &quot;Step 4: 修复 ISR 栈对齐&quot;">​</a></h3><p><strong>目标</strong>: 修改 interrupts.S 中的 ISR_NOERRCODE 和 ISR_ERRCODE 宏，确保 C handler 入口栈对齐正确。</p><p><strong>设计思路</strong>: 在 pushq %r15（最后一个 GPR）之后，额外 pushq $0 作为 8 字节对齐 padding。然后用 <code>leaq 8(%rsp), %rdi</code> 计算 InterruptFrame* 参数（跳过 padding 指向 r15），call handler，返回后 <code>addq $8, %rsp</code> 弹出 padding。两个宏（NOERRCODE 和 ERRCODE）都需要同样处理。</p><p>数学验证：NOERRCODE 宏里，CPU 5 qwords (40) + dummy 1 + GPR 15 + padding 1 = 22 qwords (176 bytes)，加上 call 的 8 字节 = 184，184 mod 16 = 8，满足 ABI。ERRCODE 宏里，CPU 6 qwords (48) + GPR 15 + padding 1 = 22 qwords (176 bytes)，加上 call 的 8 字节 = 184，同样满足。</p><p><strong>验证</strong>: 修改后 <code>make run</code>，确认不再触发 #GP。特别注意观察启动时 [MOUSE] 初始化消息出现后系统是否继续正常运行。如果 #GP 仍然出现，检查 <code>leaq 8(%rsp), %rdi</code> 那行——不要写成 <code>movq %rsp, %rdi</code>，否则 InterruptFrame* 会指向 padding 而不是 r15，导致 handler 读到错误的寄存器值。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>make run</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>观察串口输出中的以下关键信息：</p><ul><li><code>[WM] WindowManager initialised.</code>（如果有的话）— 窗口管理器初始化成功</li><li><code>[GUI] Demo rendered to framebuffer.</code> — GUI 初始画面已渲染</li><li>无 #GP 异常 — ISR 栈对齐修复生效</li></ul><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p>如果窗口没有正确显示，先检查 composite 是否被调用了（加串口打印确认）。然后检查窗口的 visible 标记——默认应该是 true。如果 blit_to 没有画面，检查离屏画布是否正确初始化（allocate_canvas 是否被调用）。draw_title_bar 需要 font_ 非空才能画文字——如果窗口创建了但标题栏是空的蓝色条，检查 font 指针。</p><p>如果 #GP 仍然出现，检查 interrupts.S 的修改是否正确——尤其是 <code>leaq 8(%rsp), %rdi</code> 那行，不要写成 <code>movq %rsp, %rdi</code>，否则 InterruptFrame* 会指向 padding 而不是 r15，导致 handler 读到错误的寄存器值。</p><p>如果你发现 raise 之后窗口没有出现在最上面，检查 update_focus 是否被调用。如果你发现 destroy 之后焦点乱了，检查 remove_at 里 was_focused 的判断——只有被删除的窗口是焦点窗口时才需要 update_focus。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>关键点</th></tr></thead><tbody><tr><td>Window 离屏画布</td><td>每个窗口独立 Canvas，避免闪烁，non-copyable</td></tr><tr><td>Z-序数组</td><td>index 0 = 底层，count-1 = 顶层，raise 做 O(n) 数组 shift</td></tr><tr><td>焦点策略</td><td>最顶层窗口自动获得焦点，update_focus O(n)</td></tr><tr><td>ISR 栈对齐</td><td>push $0 padding，leaq 8(%rsp) 跳过，总栈量 184 bytes</td></tr><tr><td>System V ABI</td><td>call 后 RSP ≡ 8 (mod 16)，编译器依赖此约定生成 movaps</td></tr><tr><td>Compositing</td><td>清屏 → 底到顶 blit → 光标 → flip</td></tr><tr><td>窗口指针数组</td><td>挪指针不挪对象，O(n) raise/remove，MAX_WINDOWS = 64</td></tr><tr><td>光标位图</td><td>16x16 uint16_t 数组，白色填充 + 黑色描边</td></tr></tbody></table>',58)])])}const b=e(n,[["render",d]]);export{h as __pageData,b as default};
